package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;

class CSVParserTest {

    private File mockFile;
    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void testParse_withValidFileAndFormat_returnsCSVParser() throws IOException {
        try (MockedConstruction<FileReader> mockedFileReader = mockConstruction(FileReader.class)) {
            CSVParser parser = CSVParser.parse(mockFile, mockFormat);
            assertNotNull(parser);
            assertEquals(mockFormat, parser.format);

            // Because CSVParser constructor sets format field, verify it
            // We cannot access private fields directly; use reflection:
            var formatField = CSVParser.class.getDeclaredField("format");
            formatField.setAccessible(true);
            assertEquals(mockFormat, formatField.get(parser));
        }
    }

    @Test
    void testParse_withNullFile_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> CSVParser.parse((File) null, mockFormat));
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void testParse_withNullFormat_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockFile, null));
        assertEquals("format", thrown.getMessage());
    }
}
